package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonPrimitive;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

public class JsonTreeReaderTest {

    private JsonTreeReader jsonTreeReader;

    @BeforeEach
    void setUp() throws Exception {
        // Create a dummy JsonPrimitive for testing
        JsonPrimitive jsonPrimitive = new JsonPrimitive("testString");

        // Create instance of JsonTreeReader with a dummy JsonElement via reflection
        // Since constructor is public JsonTreeReader(JsonElement), but JsonElement is abstract,
        // we can mock it or pass null and manually set stack.
        jsonTreeReader = new JsonTreeReader(null);

        // Use reflection to set private fields stack and stackSize
        Field stackField = JsonTreeReader.class.getDeclaredField("stack");
        stackField.setAccessible(true);
        Object[] stackArray = new Object[32];
        stackArray[0] = jsonPrimitive; // put JsonPrimitive on stack at position 0
        stackField.set(jsonTreeReader, stackArray);

        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        stackSizeField.setInt(jsonTreeReader, 1);

        // Set pathIndices array with zeros
        Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
        pathIndicesField.setAccessible(true);
        int[] pathIndices = new int[32];
        pathIndices[0] = 0;
        pathIndicesField.set(jsonTreeReader, pathIndices);

        // We need to mock peek() method to return STRING or NUMBER depending on test
        // Since peek() is public and final, we cannot mock easily with Mockito.
        // Instead, we will use reflection to replace peek() with a method that returns desired token.
        // Alternatively, create a subclass to override peek() for testing.

        // Create a subclass that overrides peek()
        jsonTreeReader = new JsonTreeReader(null) {
            @Override
            public JsonToken peek() {
                return JsonToken.STRING;
            }

            @Override
            protected Object popStack() {
                try {
                    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
                    stackField.setAccessible(true);
                    Object[] stack = (Object[]) stackField.get(this);

                    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
                    stackSizeField.setAccessible(true);
                    int stackSize = stackSizeField.getInt(this);

                    if (stackSize == 0) {
                        throw new IllegalStateException("stack is empty");
                    }

                    Object result = stack[stackSize - 1];
                    stack[stackSize - 1] = null;

                    stackSizeField.setInt(this, stackSize - 1);
                    return result;
                } catch (Exception e) {
                    throw new RuntimeException(e);
                }
            }
        };

        // Set fields again for this new instance
        stackField.setAccessible(true);
        Object[] stackArr = new Object[32];
        stackArr[0] = jsonPrimitive;
        stackField.set(jsonTreeReader, stackArr);

        stackSizeField.setAccessible(true);
        stackSizeField.setInt(jsonTreeReader, 1);

        pathIndicesField.setAccessible(true);
        int[] pathInd = new int[32];
        pathInd[0] = 0;
        pathIndicesField.set(jsonTreeReader, pathInd);
    }

    @Test
    void nextString_shouldReturnString_whenTokenIsString() throws IOException {
        String result = jsonTreeReader.nextString();
        assertEquals("testString", result);

        // Verify pathIndices[stackSize - 1] incremented
        try {
            Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
            pathIndicesField.setAccessible(true);
            int[] pathIndices = (int[]) pathIndicesField.get(jsonTreeReader);
            assertEquals(1, pathIndices[0]);
        } catch (Exception e) {
            fail(e);
        }
    }

    @Test
    void nextString_shouldReturnString_whenTokenIsNumber() throws Exception {
        // Create subclass overriding peek to return NUMBER and popStack to return JsonPrimitive number
        JsonPrimitive numberPrimitive = new JsonPrimitive(123);

        JsonTreeReader reader = new JsonTreeReader(null) {
            @Override
            public JsonToken peek() {
                return JsonToken.NUMBER;
            }

            @Override
            protected Object popStack() {
                return numberPrimitive;
            }
        };

        // Set stackSize and pathIndices
        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        stackSizeField.setInt(reader, 1);

        Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
        pathIndicesField.setAccessible(true);
        int[] pathIndices = new int[32];
        pathIndices[0] = 5;
        pathIndicesField.set(reader, pathIndices);

        String result = reader.nextString();
        assertEquals("123", result);

        // Verify pathIndices incremented
        int[] updatedPathIndices = (int[]) pathIndicesField.get(reader);
        assertEquals(6, updatedPathIndices[0]);
    }

    @Test
    void nextString_shouldThrowIllegalStateException_whenTokenIsNotStringOrNumber() throws Exception {
        // Create subclass overriding peek() to return BOOLEAN
        JsonTreeReader reader = new JsonTreeReader(null) {
            @Override
            public JsonToken peek() {
                return JsonToken.BOOLEAN;
            }
        };

        // Use reflection to set pathNames to simulate locationString() returning something
        Field pathNamesField = JsonTreeReader.class.getDeclaredField("pathNames");
        pathNamesField.setAccessible(true);
        String[] pathNames = new String[32];
        pathNames[0] = "fieldName";
        pathNamesField.set(reader, pathNames);

        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        stackSizeField.setInt(reader, 1);

        IllegalStateException thrown = assertThrows(IllegalStateException.class, reader::nextString);
        assertTrue(thrown.getMessage().contains("Expected STRING but was BOOLEAN"));
    }
}

